def longest_common_substring(a,b):
    n=len(a); m=len(b)
    dp=[0]*(m+1)
    maxlen=0
    for i in range(1,n+1):
        new=[0]*(m+1)
        for j in range(1,m+1):
            if a[i-1]==b[j-1]:
                new[j]=dp[j-1]+1
                if new[j]>maxlen:
                    maxlen=new[j]
            else:
                new[j]=0
        dp=new
    return maxlen

def similarity_score2(query, text):
    a=normalize(query)
    b=normalize(text)
    if len(a)==0:
        return 0
    lcss = longest_common_substring(a,b)/len(a)
    f1 = token_f1(a,b)
    sm = difflib.SequenceMatcher(a=a, b=b).ratio()
    # combine: maybe weighted average or max of lcss and sm? We'll take max of lcss and sm for char-level evidence, and also consider f1.
    return max(lcss, sm, f1)

